import { Router } from 'express';
import { forgotPassword, login, logout, me, refresh, register, resetPassword, verifyEmail, } from '../controllers/auth.controller.js';
import { authenticate } from '../middleware/auth.middleware.js';
import { validateRequest } from '../middleware/validate.middleware.js';
import { forgotPasswordValidator, loginValidator, registerValidator, resetPasswordValidator, verifyEmailValidator, } from '../validators/auth.validator.js';
export const authRouter = Router();
authRouter.post('/register', registerValidator, validateRequest, register);
authRouter.post('/verify-email', verifyEmailValidator, validateRequest, verifyEmail);
authRouter.post('/login', loginValidator, validateRequest, login);
authRouter.post('/refresh', refresh);
authRouter.post('/forgot-password', forgotPasswordValidator, validateRequest, forgotPassword);
authRouter.post('/reset-password', resetPasswordValidator, validateRequest, resetPassword);
authRouter.get('/me', authenticate, me);
authRouter.post('/logout', authenticate, logout);
